import{j as e,H as w,L as i,u as b,N as g}from"./index-CNEO7YzK.js";import{g as v}from"./blogPosts-C9kuMden.js";const j=({title:a,subtitle:t,date:c,readTime:d,section:p,children:x,slug:M,tags:l,dateISO:m,meta:s})=>{const r=p==="blog"?"Blog":"Learn",h=p==="blog"?"/blog":"/learn",n="https://crox.io",o=s?.canonical?`${n}${s.canonical}`:void 0,f={"@context":"https://schema.org","@type":"Article",headline:a,description:s?.description||t,datePublished:m||new Date().toISOString().split("T")[0],author:{"@type":"Person",name:"Adam Field"},publisher:{"@type":"Organization",name:"Crox",logo:{"@type":"ImageObject",url:`${n}/logo.png`}},url:o||`${n}${s?.canonical||"/"}`,keywords:l?.join(", ")||""},y={"@context":"https://schema.org","@type":"BreadcrumbList",itemListElement:[{position:1,name:"Home",item:n},{position:2,name:r,item:`${n}${h}`},{position:3,name:a,item:o||`${n}${s?.canonical||"/"}`}].map(u=>({"@type":"ListItem",position:u.position,name:u.name,item:u.item}))};return e.jsxs(e.Fragment,{children:[e.jsxs(w,{children:[e.jsxs("title",{children:[a," — Crox"]}),e.jsx("meta",{name:"description",content:s?.description||t}),e.jsx("meta",{name:"robots",content:"index, follow, max-snippet:-1, max-image-preview:large"}),e.jsx("meta",{name:"author",content:"Adam Field"}),o&&e.jsx("link",{rel:"canonical",href:o}),e.jsx("meta",{property:"og:title",content:a}),e.jsx("meta",{property:"og:description",content:s?.description||t}),e.jsx("meta",{property:"og:type",content:"article"}),e.jsx("meta",{property:"og:site_name",content:"Crox"}),o&&e.jsx("meta",{property:"og:url",content:o}),s?.ogImage&&e.jsx("meta",{property:"og:image",content:s.ogImage}),m&&e.jsx("meta",{property:"article:published_time",content:m}),e.jsx("meta",{property:"article:author",content:"Adam Field"}),l&&l.length>0&&e.jsx("meta",{property:"article:tag",content:l.join(", ")}),e.jsx("meta",{name:"twitter:card",content:"summary_large_image"}),e.jsx("meta",{name:"twitter:title",content:a}),e.jsx("meta",{name:"twitter:description",content:s?.description||t}),e.jsx("script",{type:"application/ld+json",children:JSON.stringify(f)}),e.jsx("script",{type:"application/ld+json",children:JSON.stringify(y)})]}),e.jsxs("article",{className:"w-full max-w-[900px] mx-auto px-4 sm:px-6 py-16 sm:py-24",children:[e.jsxs("nav",{className:"mb-12 text-[0.85rem] text-fg-dim",children:[e.jsx(i,{to:"/",className:"text-fg border-b border-border pb-px hover:border-accent transition-colors",children:"Home"}),e.jsx("span",{className:"mx-3",children:"/"}),e.jsx(i,{to:h,className:"text-fg border-b border-border pb-px hover:border-accent transition-colors",children:r}),e.jsx("span",{className:"mx-3",children:"/"}),e.jsx("span",{children:a})]}),e.jsxs("header",{className:"mb-12",children:[e.jsx("h1",{className:"font-serif font-normal text-[3.2rem] leading-[1.15] text-fg mb-4",children:a}),e.jsx("p",{className:"text-[1.1rem] text-fg-dim mb-6",children:t}),e.jsxs("div",{className:"flex flex-wrap items-center gap-6 text-[0.85rem] text-fg-dim border-t border-border pt-6",children:[e.jsxs("div",{children:[e.jsx("span",{className:"text-fg-dim",children:"Published"}),e.jsx("span",{className:"ml-2",children:c})]}),e.jsxs("div",{children:[e.jsx("span",{className:"text-fg-dim",children:"Read time"}),e.jsx("span",{className:"ml-2",children:d})]})]})]}),e.jsx("div",{className:"prose prose-invert max-w-none mb-16",children:x}),e.jsxs("div",{className:"bg-surface border border-border rounded-none p-8 sm:p-10 mb-16",children:[e.jsx("h3",{className:"font-serif font-normal text-[1.6rem] text-fg mb-4",children:"Ready to integrate AI into your business?"}),e.jsx("p",{className:"text-[0.95rem] text-fg-dim leading-[1.8] mb-6",children:"See how Model Context Protocol (MCP) can connect your AI assistant to all your business tools. Book a call with our team to discuss your specific needs."}),e.jsx("a",{href:"https://calendar.app.google/3avUXyXnctfWpyHF7",target:"_blank",rel:"noopener noreferrer",className:"inline-block font-mono text-[0.8rem] font-medium tracking-[0.15em] uppercase text-fg bg-accent px-10 py-4 hover:opacity-90 transition-opacity",children:"Book a Call"})]}),e.jsxs("div",{className:"border-t border-border pt-12",children:[e.jsxs("div",{className:"text-[0.7rem] tracking-[0.2em] uppercase text-fg-dim mb-8 flex items-center gap-4",children:["More from ",r,e.jsx("span",{className:"flex-1 h-px bg-border"})]}),e.jsxs("p",{className:"text-[0.95rem] text-fg-dim",children:["Explore more insights and guides in our ",r.toLowerCase()," section."]}),e.jsxs(i,{to:h,className:"inline-block mt-4 font-mono text-[0.8rem] font-medium tracking-[0.15em] uppercase text-fg border-b border-border pb-px hover:border-accent transition-colors",children:["View All ",r," Posts"]})]})]})]})},N=()=>e.jsxs("div",{className:"space-y-6",children:[e.jsx("p",{className:"text-[0.95rem] text-fg-dim leading-[1.8]",children:"You've probably noticed that AI assistants like ChatGPT can answer questions and write content, but they can't actually see your business data. Your CRM, accounting software, email inbox—they're all invisible to the AI. This isn't a limitation of the AI itself. It's a problem of how systems communicate with each other."}),e.jsx("p",{className:"text-[0.95rem] text-fg-dim leading-[1.8]",children:"For years, connecting different business tools meant either paying for expensive custom integrations or hiring developers. But there's a simpler path now. A new standard called Model Context Protocol (MCP) is making it possible for anyone to safely connect AI assistants to their business systems without technical expertise."}),e.jsxs("div",{className:"text-[0.7rem] tracking-[0.2em] uppercase text-fg-dim my-12 flex items-center gap-4",children:["What actually needs to happen",e.jsx("span",{className:"flex-1 h-px bg-border"})]}),e.jsx("p",{className:"text-[0.95rem] text-fg-dim leading-[1.8]",children:"Think of connecting an AI to your business tools like building a translator. Your AI speaks one language. Your CRM, accounting software, and email all speak different languages. For them to work together, you need a translation layer in the middle."}),e.jsx("p",{className:"text-[0.95rem] text-fg-dim leading-[1.8]",children:"This translator does three critical things. First, it authenticates your AI assistant so it can prove it's allowed to access your systems. Second, it reads data from your tools and translates it into a format the AI understands. Third, it validates what the AI wants to do before executing it—so you maintain control."}),e.jsx("blockquote",{className:"border-l-2 border-accent pl-6 my-8 text-fg italic font-serif text-[1.1rem]",children:"Most businesses still think they need a developer to do this. They don't. That's what changed."}),e.jsxs("div",{className:"text-[0.7rem] tracking-[0.2em] uppercase text-fg-dim my-12 flex items-center gap-4",children:["How Model Context Protocol makes this simple",e.jsx("span",{className:"flex-1 h-px bg-border"})]}),e.jsx("p",{className:"text-[0.95rem] text-fg-dim leading-[1.8]",children:"Model Context Protocol is a standard created by Anthropic that lets business tools communicate directly with AI. It's built specifically to be straightforward for non-technical people to set up and maintain."}),e.jsx("p",{className:"text-[0.95rem] text-fg-dim leading-[1.8]",children:"Here's the practical difference. Before MCP, you'd either accept that your AI couldn't see your data, or you'd pay thousands to a developer to build a custom bridge. Now, you can use MCP to connect your AI to Xero, Shopify, HubSpot, Slack, or any other tool you use. The process is designed to be accessible, even if you've never written code."}),e.jsx("p",{className:"text-[0.95rem] text-fg-dim leading-[1.8]",children:`The connection happens through what's called a "server." This server sits between your AI and your business tools. It handles authentication using the API keys you already manage. It enforces permissions so the AI can only access what you explicitly allow. And it keeps a log of everything that happens, so you always know what the AI did and when.`}),e.jsx("h2",{className:"font-serif font-normal text-[1.6rem] mb-4 mt-8",children:"A practical example from a UK accounting firm"}),e.jsx("p",{className:"text-[0.95rem] text-fg-dim leading-[1.8]",children:"Let's say you run a small accounting practice with 12 staff. You use Xero for accounting, HubSpot for client management, and Gmail for email. Right now, when a client calls with a question, your team has to jump between three systems to get the full picture."}),e.jsx("p",{className:"text-[0.95rem] text-fg-dim leading-[1.8]",children:`With MCP connected, you can ask an AI assistant: "Tell me about our relationship with Johnson Manufacturing—show me their last three invoices, open support tickets, and any emails from them in the last month." The AI would fetch that data through the MCP servers connected to your tools, synthesize it, and give you a complete summary. The data never leaves your systems. The AI is just reading what you've authorized it to see.`}),e.jsxs("div",{className:"text-[0.7rem] tracking-[0.2em] uppercase text-fg-dim my-12 flex items-center gap-4",children:["Setting up MCP safely",e.jsx("span",{className:"flex-1 h-px bg-border"})]}),e.jsx("p",{className:"text-[0.95rem] text-fg-dim leading-[1.8]",children:"Security is built into the process, not added afterward. When you set up an MCP connection, you choose exactly what permissions the AI receives. You're not giving it a master key to your systems. You're giving it a specific, limited key that can only do what you've defined."}),e.jsx("p",{className:"text-[0.95rem] text-fg-dim leading-[1.8]",children:"For example, you might allow the AI to read invoices from Xero, but not to create or delete them. You might allow it to read client information from HubSpot, but not to modify it. You control the boundaries. The MCP server enforces those boundaries every single time the AI tries to do something."}),e.jsx("p",{className:"text-[0.95rem] text-fg-dim leading-[1.8]",children:"Audit logs are created automatically. Every query the AI runs, every piece of data it accesses, every action it takes—it's all recorded. This means you can see exactly what happened and when, which is critical for compliance in regulated industries like accounting or legal."}),e.jsx("h2",{className:"font-serif font-normal text-[1.6rem] mb-4 mt-8",children:"What you can build once the connection exists"}),e.jsx("p",{className:"text-[0.95rem] text-fg-dim leading-[1.8]",children:"Once MCP is set up, the possibilities are genuinely different from what you could do before. Your AI assistant becomes not just a conversational tool, but an extension of your business operations."}),e.jsx("p",{className:"text-[0.95rem] text-fg-dim leading-[1.8]",children:"An accountant might use an AI to automatically summarize client activity, identify potential VAT issues, or flag unusual transactions. A legal practice might use it to search contracts across their system, extract relevant clauses, and check compliance against a template. A service business might have it manage scheduling, send reminders, and draft follow-up emails—all without touching your actual systems unless explicitly instructed."}),e.jsx("p",{className:"text-[0.95rem] text-fg-dim leading-[1.8]",children:"The key difference is that all of this happens with your data staying in your systems. Nothing is sent to external servers. Nothing is trained into public models. The AI is reading and working with your data safely, securely, and with full audit trails."}),e.jsxs("div",{className:"text-[0.7rem] tracking-[0.2em] uppercase text-fg-dim my-12 flex items-center gap-4",children:["The next step",e.jsx("span",{className:"flex-1 h-px bg-border"})]}),e.jsx("p",{className:"text-[0.95rem] text-fg-dim leading-[1.8]",children:"If you're running a small or medium business and you've been waiting for AI to be truly useful with your real business data, the wait is effectively over. MCP isn't a future technology anymore. It's practical, implementable, and accessible to non-technical teams."}),e.jsx("p",{className:"text-[0.95rem] text-fg-dim leading-[1.8]",children:"The process starts by understanding what specific problems you want to solve. Do you want to reduce manual data entry? Improve client communication? Automate compliance checks? Once you know that, setting up the right MCP connections becomes straightforward."}),e.jsxs("p",{className:"text-[0.95rem] text-fg-dim leading-[1.8]",children:[e.jsx(i,{to:"/ai-integration",className:"text-fg border-b border-border pb-px hover:border-accent transition-colors",children:"Explore our AI integration platform"})," ","to see how MCP can work with your specific tools and workflows. We'll help you understand what's possible, what's safe, and how to implement it without risk."]})]}),k=()=>e.jsxs("div",{className:"space-y-6",children:[e.jsx("p",{className:"text-[0.95rem] text-fg-dim leading-[1.8]",children:'Every accounting firm we talk to has asked the same question: "What can AI actually do for us right now?" The answer is more than they expect, and probably different than they think.'}),e.jsx("p",{className:"text-[0.95rem] text-fg-dim leading-[1.8]",children:"AI isn't going to replace accountants. But it absolutely can eliminate the tedious parts of the job—the manual data entry, the chasing of receipts, the repetitive compliance checks. And in 2026, with Model Context Protocol connecting AI to your existing systems like Xero, QuickBooks, or Sage, the practicality of this is no longer theoretical."}),e.jsxs("div",{className:"text-[0.7rem] tracking-[0.2em] uppercase text-fg-dim my-12 flex items-center gap-4",children:["Where AI is actually useful in accounting",e.jsx("span",{className:"flex-1 h-px bg-border"})]}),e.jsx("p",{className:"text-[0.95rem] text-fg-dim leading-[1.8]",children:"Start with transaction categorization. This is pure busywork. A client sends over a CSV of transactions. Someone on your team manually checks each one, codes it correctly, and files it. An AI with access to your accounting software can read a transaction description, check historical patterns, and suggest the right category with high accuracy. For a typical firm processing hundreds of transactions monthly, this saves 10-15 hours per week."}),e.jsx("p",{className:"text-[0.95rem] text-fg-dim leading-[1.8]",children:"Bank reconciliation is another obvious candidate. Your team downloads bank statements, manually matches them to transactions in Xero or QuickBooks, and flags discrepancies. An AI connected via MCP can do this automatically. It reads the bank statement, compares it to your accounting system, identifies unmatched transactions, and flags potential errors. It can even suggest explanations for timing differences."}),e.jsx("p",{className:"text-[0.95rem] text-fg-dim leading-[1.8]",children:"Invoice management becomes dramatically simpler. When a client email arrives with a PDF invoice, an AI can extract the vendor name, invoice number, amount, and due date automatically. It can check whether this vendor already exists in your system, flag invoices from unfamiliar suppliers, and route them to the right person. For larger firms processing dozens of invoices daily, this is transformative."}),e.jsx("blockquote",{className:"border-l-2 border-accent pl-6 my-8 text-fg italic font-serif text-[1.1rem]",children:"The firms winning right now aren't using AI to do accounting better. They're using it to eliminate the parts of accounting that don't require human judgment."}),e.jsx("h2",{className:"font-serif font-normal text-[1.6rem] mb-4 mt-8",children:"Compliance and error detection"}),e.jsx("p",{className:"text-[0.95rem] text-fg-dim leading-[1.8]",children:"Here's where AI becomes less about saving time and more about reducing risk. A well-configured AI system connected to your accounting software can monitor transactions continuously and flag potential issues before they become problems."}),e.jsx("p",{className:"text-[0.95rem] text-fg-dim leading-[1.8]",children:"Unusual transaction patterns stand out immediately. If a client typically receives £50,000 monthly in revenue but suddenly receives £500,000 in a single day, the AI flags it. If round-number transactions start appearing when they usually don't, the AI catches it. If money moves to a new bank account without documented authorization, the AI alerts your team."}),e.jsx("p",{className:"text-[0.95rem] text-fg-dim leading-[1.8]",children:"For VAT compliance, an AI can read through transactions and identify potential issues—missing VAT codes, reversed charges that don't qualify, transactions that might trigger VAT investigations. This isn't replacing your accountant's knowledge. It's giving your team a second set of eyes that never gets tired."}),e.jsx("p",{className:"text-[0.95rem] text-fg-dim leading-[1.8]",children:"The key here is that the AI stays within your systems. It doesn't send client data anywhere. It doesn't train on sensitive information. Using Model Context Protocol, it reads what it's authorized to read, performs analysis, and reports back. Everything stays secure."}),e.jsxs("div",{className:"text-[0.7rem] tracking-[0.2em] uppercase text-fg-dim my-12 flex items-center gap-4",children:["Real workflow example: month-end close",e.jsx("span",{className:"flex-1 h-px bg-border"})]}),e.jsx("p",{className:"text-[0.95rem] text-fg-dim leading-[1.8]",children:"Here's how an accounting firm might actually use this. Let's say it's the 28th of the month and you're starting the close process for 20 clients."}),e.jsx("p",{className:"text-[0.95rem] text-fg-dim leading-[1.8]",children:"Your AI assistant, connected via MCP to Xero and your email system, automatically gathers preliminary data. It pulls the trial balance for each client. It identifies any unreconciled accounts. It extracts information from any month-end adjustment emails your team has sent. It flags transactions that look unusual or require follow-up."}),e.jsx("p",{className:"text-[0.95rem] text-fg-dim leading-[1.8]",children:"By the time your team sits down to do the actual close, 80% of the groundwork is done. The anomalies are already identified. The documentation is already gathered. Your accountants focus on the decisions and judgments that actually require their expertise."}),e.jsx("p",{className:"text-[0.95rem] text-fg-dim leading-[1.8]",children:"A month-end close that usually takes three days now takes one and a half. That's two days per month per client. For a 20-person team managing 50 clients, that's significant capacity freed up."}),e.jsx("h2",{className:"font-serif font-normal text-[1.6rem] mb-4 mt-8",children:"Client communication and reporting"}),e.jsx("p",{className:"text-[0.95rem] text-fg-dim leading-[1.8]",children:"Here's something less obvious: AI is phenomenal at explaining things. When you send a client a set of financial statements, they often have questions. An AI with access to their accounting data can answer those questions immediately and accurately."}),e.jsx("p",{className:"text-[0.95rem] text-fg-dim leading-[1.8]",children:`Client asks "Why are professional fees up 20% this month?" The AI reads the transactions and explains that it's because they paid their quarterly accountancy bill. Client asks "What was our best month this year?" The AI checks the records and gives them the answer with supporting data.`}),e.jsx("p",{className:"text-[0.95rem] text-fg-dim leading-[1.8]",children:`More importantly, this frees your team from answering routine questions. They're not sitting on email saying "Revenue was £340,000 in February." They're focused on strategic conversations, tax planning, and business advice. The AI handles the lookups.`}),e.jsxs("div",{className:"text-[0.7rem] tracking-[0.2em] uppercase text-fg-dim my-12 flex items-center gap-4",children:["The implementation question",e.jsx("span",{className:"flex-1 h-px bg-border"})]}),e.jsx("p",{className:"text-[0.95rem] text-fg-dim leading-[1.8]",children:"The realistic conversation is this: you probably don't need to build custom AI. You need to connect an AI assistant to your existing tools. That's what MCP does. It lets you configure what data an AI can access and what actions it can take. No coding required."}),e.jsx("p",{className:"text-[0.95rem] text-fg-dim leading-[1.8]",children:"You'd start by identifying the single workflow that causes the most pain or costs the most time. Maybe it's bank reconciliation. Maybe it's invoice processing. You connect the AI to those systems with carefully defined permissions. You test it thoroughly. You train your team on how to use it. Then you expand."}),e.jsx("p",{className:"text-[0.95rem] text-fg-dim leading-[1.8]",children:"The timeline matters. You're not looking at a 12-month implementation. A well-planned MCP integration typically takes 4-6 weeks from planning to production, often with a single developer or consultant."}),e.jsxs("div",{className:"text-[0.7rem] tracking-[0.2em] uppercase text-fg-dim my-12 flex items-center gap-4",children:["What's holding firms back",e.jsx("span",{className:"flex-1 h-px bg-border"})]}),e.jsx("p",{className:"text-[0.95rem] text-fg-dim leading-[1.8]",children:'Most of the resistance we see comes from uncertainty, not from the technology itself. "Is this secure?" "Will this break our compliance?" "Are we liable if the AI makes a mistake?" These are legitimate questions.'}),e.jsx("p",{className:"text-[0.95rem] text-fg-dim leading-[1.8]",children:"The honest answer is that with MCP, security is stronger than many manual processes. The AI operates with explicit, auditable permissions. Every action is logged. Your data never leaves your systems. You maintain absolute control over what the AI can and cannot do."}),e.jsx("p",{className:"text-[0.95rem] text-fg-dim leading-[1.8]",children:"For liability, the same principle applies. The AI isn't making independent decisions. It's assisting your team. Your accountants review its work before it has any effect. You're not delegating; you're augmenting."}),e.jsx("p",{className:"text-[0.95rem] text-fg-dim leading-[1.8]",children:"The firms that are moving forward are the ones that are treating AI not as a replacement, but as infrastructure. Just like you installed accounting software to eliminate manual ledgers, you're now installing AI to eliminate tedious data work."}),e.jsxs("p",{className:"text-[0.95rem] text-fg-dim leading-[1.8]",children:[e.jsx(i,{to:"/ai-integration",className:"text-fg border-b border-border pb-px hover:border-accent transition-colors",children:"Talk to our team about integrating AI"})," ","into your accounting practice. We can map out specifically what would work for your firm, what the timeline looks like, and what the actual time savings would be for your team."]})]}),I=()=>e.jsxs("div",{className:"space-y-6",children:[e.jsx("p",{className:"text-[0.95rem] text-fg-dim leading-[1.8]",children:`You've probably asked an AI assistant about one of your customers and gotten a blank stare. You ask, "Tell me about Acme Corporation's history with us" and the AI says it doesn't have access to that data. Of course it doesn't. Your CRM is sitting on your server. The AI has no way to reach it.`}),e.jsx("p",{className:"text-[0.95rem] text-fg-dim leading-[1.8]",children:"This isn't a limitation of the AI. It's a technical barrier. And for years, breaking through that barrier meant hiring a developer or accepting that your AI would always be disconnected from your real customer data. But that's changing. Model Context Protocol is solving this problem in a way that's practical for non-technical teams."}),e.jsxs("div",{className:"text-[0.7rem] tracking-[0.2em] uppercase text-fg-dim my-12 flex items-center gap-4",children:["Why your CRM is invisible to AI",e.jsx("span",{className:"flex-1 h-px bg-border"})]}),e.jsx("p",{className:"text-[0.95rem] text-fg-dim leading-[1.8]",children:"Here's the technical reality. AI systems like ChatGPT or Claude are text-based. They work with information that's given to them directly in a conversation. They can't browse your network. They can't log into your software. They can't query your database."}),e.jsx("p",{className:"text-[0.95rem] text-fg-dim leading-[1.8]",children:"Your CRM—whether it's HubSpot, Salesforce, Pipedrive, or something else—is secured behind authentication. Only authorized users with the right credentials can access it. The AI doesn't have credentials. Even if it did, asking every CRM vendor to build custom AI integrations would be chaotic and expensive."}),e.jsx("p",{className:"text-[0.95rem] text-fg-dim leading-[1.8]",children:"So the system stays isolated. You use your CRM for customer data, deals, and history. You ask the AI questions separately. The two never talk. And this kills a huge range of possibilities. Your AI could draft a personalized email to a customer, but it doesn't know their purchase history. It could analyze sales patterns, but it doesn't have access to your actual deals."}),e.jsx("blockquote",{className:"border-l-2 border-accent pl-6 my-8 text-fg italic font-serif text-[1.1rem]",children:"The AI isn't being stubborn. It's being secure. It just doesn't know how to talk to your CRM safely."}),e.jsx("h2",{className:"font-serif font-normal text-[1.6rem] mb-4 mt-8",children:"What Model Context Protocol changes"}),e.jsx("p",{className:"text-[0.95rem] text-fg-dim leading-[1.8]",children:"MCP creates a secure channel between your CRM and your AI assistant. Think of it as a translator that speaks both languages."}),e.jsx("p",{className:"text-[0.95rem] text-fg-dim leading-[1.8]",children:"Here's how it works. First, you set up an MCP server specifically for your CRM. This server has credentials to access your CRM. You define exactly what permissions it has—maybe it can read customer records and deal information, but can't delete anything or modify customer data. You decide the boundaries."}),e.jsx("p",{className:"text-[0.95rem] text-fg-dim leading-[1.8]",children:`Second, you connect your AI assistant to this MCP server. Now the AI can ask the server questions like "Show me all deals in the pipeline for customer X" or "What's the history of interactions with this account." The server translates that request, queries your CRM safely using its authorized credentials, and returns the data to the AI.`}),e.jsx("p",{className:"text-[0.95rem] text-fg-dim leading-[1.8]",children:"Third, every single interaction is logged. You can see exactly what data the AI requested and when. This means you have complete visibility and control."}),e.jsx("p",{className:"text-[0.95rem] text-fg-dim leading-[1.8]",children:"The critical difference from the past: you don't need custom development for every CRM. MCP is a standard. As long as your CRM has an API—which all modern ones do—you can set this up."}),e.jsxs("div",{className:"text-[0.7rem] tracking-[0.2em] uppercase text-fg-dim my-12 flex items-center gap-4",children:["Practical scenarios",e.jsx("span",{className:"flex-1 h-px bg-border"})]}),e.jsx("p",{className:"text-[0.95rem] text-fg-dim leading-[1.8]",children:"Let's make this concrete. Say you run a SaaS company with 15 salespeople and use Pipedrive as your CRM. Your sales process requires personalized outreach, but most of your team spends time manually pulling customer history before they can send a relevant email."}),e.jsx("p",{className:"text-[0.95rem] text-fg-dim leading-[1.8]",children:'With MCP connected, a salesperson can say to an AI assistant: "Draft a follow-up email to Sarah Chen. Review her purchase history and our last three interactions before you write it." The AI reads her profile, deal history, and interaction notes from Pipedrive through the MCP server. It drafts an email that references her specific situation, recent wins, or concerns. The salesperson reviews it and sends it. No context switching. No manual data gathering.'}),e.jsx("p",{className:"text-[0.95rem] text-fg-dim leading-[1.8]",children:`Or consider a customer success scenario. You have a support team using HubSpot to track customer issues. When a ticket comes in, an agent could ask the AI: "Tell me what happened with this customer's onboarding" or "Why did they originally buy from us?" The AI fetches the history and gives the agent the full context in seconds. The resolution is faster and more thoughtful because the agent has the facts.`}),e.jsx("p",{className:"text-[0.95rem] text-fg-dim leading-[1.8]",children:"For account-based marketing, it's even more powerful. Your AI can analyze all deals in a specific sector, identify buying patterns, and suggest which accounts to target next. It can review past campaigns to a client and suggest what messaging worked. This isn't guessing. It's data-driven recommendations from your actual history."}),e.jsx("h2",{className:"font-serif font-normal text-[1.6rem] mb-4 mt-8",children:"The security reality"}),e.jsx("p",{className:"text-[0.95rem] text-fg-dim leading-[1.8]",children:'The first objection we hear is always security. "Are you exposing my CRM by connecting it to an AI?" The answer is no, for a specific reason.'}),e.jsx("p",{className:"text-[0.95rem] text-fg-dim leading-[1.8]",children:"With MCP, the data flow is controlled and limited. The AI doesn't get a login to your CRM. It doesn't get a master API key. It gets a request-response channel with defined permissions. You're not broadcasting your CRM on the internet. You're creating a one-way reading relationship where specific data can flow from your system to the AI when authorized."}),e.jsx("p",{className:"text-[0.95rem] text-fg-dim leading-[1.8]",children:"The second piece is auditability. Everything is logged. If you need to investigate whether the AI accessed sensitive information, you have the full record. If you need to prove compliance, the logs are there. If a team member is concerned about data leakage, you can show them exactly what data moved and when."}),e.jsx("p",{className:"text-[0.95rem] text-fg-dim leading-[1.8]",children:`And the permissions are granular. You're not saying "let the AI see everything." You're saying "let the AI read customer names, company size, and recent deals, but not pricing or contract terms." You control the scope down to the field level.`}),e.jsxs("div",{className:"text-[0.7rem] tracking-[0.2em] uppercase text-fg-dim my-12 flex items-center gap-4",children:["Why it matters that this is a standard",e.jsx("span",{className:"flex-1 h-px bg-border"})]}),e.jsx("p",{className:"text-[0.95rem] text-fg-dim leading-[1.8]",children:"The reason MCP is actually changing things—not just theoretically, but practically—is that it's a standard. This means it doesn't matter if you use HubSpot, Salesforce, Pipedrive, or Zoho. The MCP server pattern is the same."}),e.jsx("p",{className:"text-[0.95rem] text-fg-dim leading-[1.8]",children:"For the first time, connecting an AI to your CRM doesn't require a custom integration. You're not waiting for HubSpot to build an AI integration. You're not paying a developer tens of thousands of pounds to build a bridge. You're using a standard pattern that any developer, or even a knowledgeable non-technical person, can set up."}),e.jsx("p",{className:"text-[0.95rem] text-fg-dim leading-[1.8]",children:"This is huge for businesses of all sizes. Enterprises that could afford custom development could always do this. But now a 10-person agency, a 20-person consultancy, a growing SaaS team—they can all connect their CRM to AI. The cost dropped from five figures to low four figures. The timeline dropped from three months to three weeks."}),e.jsxs("div",{className:"text-[0.7rem] tracking-[0.2em] uppercase text-fg-dim my-12 flex items-center gap-4",children:["Getting started",e.jsx("span",{className:"flex-1 h-px bg-border"})]}),e.jsx("p",{className:"text-[0.95rem] text-fg-dim leading-[1.8]",children:"If you're running a business with a CRM and you've been frustrated that your AI assistant can't see your data, the solution is within reach. Start by understanding what specific workflows would change if the AI had CRM access."}),e.jsx("p",{className:"text-[0.95rem] text-fg-dim leading-[1.8]",children:"Maybe it's sales outreach. Maybe it's customer success. Maybe it's marketing analysis. Pick one. Define what data the AI needs to see. Define what actions, if any, it should be allowed to take. Then set up the MCP connection with clear permissions."}),e.jsxs("p",{className:"text-[0.95rem] text-fg-dim leading-[1.8]",children:[e.jsx(i,{to:"/ai-integration",className:"text-fg border-b border-border pb-px hover:border-accent transition-colors",children:"Discuss your CRM integration with our team"})," ","to understand what's possible, what's safe, and what the actual workflow changes would be for your organization. We'll map out the specific data your AI needs and design the MCP connection with the right boundaries."]})]}),A=()=>e.jsxs("div",{className:"space-y-6",children:[e.jsx("p",{className:"text-[0.95rem] text-fg-dim leading-[1.8]",children:"Time is what every small business owner measures in. Not quarterly projections. Not abstract metrics. Hours. Hours spent on repetitive tasks. Hours that could go to growth, to clients, to actually building something."}),e.jsx("p",{className:"text-[0.95rem] text-fg-dim leading-[1.8]",children:'AI is finally making a dent in this. And not in the speculative way—"AI could eventually do this." But in the real way. Right now. UK small businesses are actually saving 10+ hours per week by connecting AI assistants to their existing tools using Model Context Protocol.'}),e.jsxs("div",{className:"text-[0.7rem] tracking-[0.2em] uppercase text-fg-dim my-12 flex items-center gap-4",children:["1. Automating email and scheduling",e.jsx("span",{className:"flex-1 h-px bg-border"})]}),e.jsx("p",{className:"text-[0.95rem] text-fg-dim leading-[1.8]",children:"A digital marketing agency in Manchester was spending roughly 8 hours per week on client email management. Sorting inquiries, drafting responses, checking project timelines, confirming availability. Necessary, but soul-crushing."}),e.jsx("p",{className:"text-[0.95rem] text-fg-dim leading-[1.8]",children:"They connected an AI to their Gmail and their project management tool via MCP. Now, when a client email comes in, the AI reads it, checks what the client has previously worked on, verifies team availability, and drafts a response. The team member reviews it, makes minor changes if needed, and sends. What took 15 minutes now takes 2 minutes."}),e.jsx("p",{className:"text-[0.95rem] text-fg-dim leading-[1.8]",children:"If you're processing 30 client emails a week, that's 6 hours reclaimed just from faster email handling. And it's not just faster—the responses are more personalized because the AI knows the client's history."}),e.jsx("h2",{className:"font-serif font-normal text-[1.6rem] mb-4 mt-8",children:"2. Invoice processing and bookkeeping"}),e.jsx("p",{className:"text-[0.95rem] text-fg-dim leading-[1.8]",children:"A plumbing business in Bristol receives invoices from suppliers through multiple channels—email, post, sometimes via their suppliers' portals. Someone has to manually enter these into their accounting software. Check details. Code them correctly. Follow up on missing information."}),e.jsx("p",{className:"text-[0.95rem] text-fg-dim leading-[1.8]",children:"By connecting their accounting software and email with an MCP server, they automated this entirely. The AI extracts invoice details automatically. It matches them to existing suppliers. It codes them based on historical patterns. For invoices with unusual details, it flags them for a human to review. The rest are automatically filed."}),e.jsx("p",{className:"text-[0.95rem] text-fg-dim leading-[1.8]",children:"Previously: 8 invoices per day, 3 minutes each, 24 minutes daily, nearly 2 hours weekly. Now: AI processes them automatically, a human spot-checks on Fridays for 20 minutes. Net saving: about 90 minutes per week."}),e.jsx("blockquote",{className:"border-l-2 border-accent pl-6 my-8 text-fg italic font-serif text-[1.1rem]",children:"The businesses winning aren't the ones using the fanciest AI. They're the ones using AI to eliminate paperwork."}),e.jsx("h2",{className:"font-serif font-normal text-[1.6rem] mb-4 mt-8",children:"3. Customer follow-up and support triage"}),e.jsx("p",{className:"text-[0.95rem] text-fg-dim leading-[1.8]",children:"A boutique recruitment consultancy in London manages dozens of active placements simultaneously. Each placement requires check-ins with the candidate, updates to the hiring manager, and occasional issue resolution. The consultant managing these accounts spends enormous time just keeping track of who needs what."}),e.jsx("p",{className:"text-[0.95rem] text-fg-dim leading-[1.8]",children:"Using MCP connected to their CRM and email, they created an AI workflow. Daily, the AI reviews all active placements and identifies which candidates and managers haven't been contacted in over a week. It drafts personalized check-in emails based on the specific placement context. The consultant approves the batch in 10 minutes and they send automatically."}),e.jsx("p",{className:"text-[0.95rem] text-fg-dim leading-[1.8]",children:"Previously: One consultant, manually checking 30 placements, identifying who needs contact, drafting emails individually. 3 hours weekly minimum. Now: AI handles the routine check-ins, the consultant focuses only on complex issues or real problems that need personal attention. Saving: 2.5 hours per week."}),e.jsx("h2",{className:"font-serif font-normal text-[1.6rem] mb-4 mt-8",children:"4. Data consolidation and reporting"}),e.jsx("p",{className:"text-[0.95rem] text-fg-dim leading-[1.8]",children:"A web design studio in Leeds uses three different systems: one for project management, one for invoicing, one for time tracking. At the end of each month, the business owner manually pulls data from all three to understand profitability, capacity utilization, and project health."}),e.jsx("p",{className:"text-[0.95rem] text-fg-dim leading-[1.8]",children:'By connecting all three via MCP, they can ask their AI assistant a single question: "Give me a monthly profitability report by project type." The AI consolidates data from all systems, calculates margins, identifies projects that ran over, and produces a summary. What took 3-4 hours monthly now takes 20 minutes because the AI pulls the data instead of a human.'}),e.jsx("p",{className:"text-[0.95rem] text-fg-dim leading-[1.8]",children:"Saving: Roughly 45 minutes per month, which might not sound huge, but it's also the difference between a report that never gets done and a report that actually informs decisions."}),e.jsxs("div",{className:"text-[0.7rem] tracking-[0.2em] uppercase text-fg-dim my-12 flex items-center gap-4",children:["5. Client communication at scale",e.jsx("span",{className:"flex-1 h-px bg-border"})]}),e.jsx("p",{className:"text-[0.95rem] text-fg-dim leading-[1.8]",children:`A consulting firm in Nottingham has 50+ active clients. Each client needs occasional status updates, progress summaries, or answers to routine questions. The business development manager was essentially spending 2-3 hours weekly just answering repetitive "how's the project going" or "what's the cost to date" questions.`}),e.jsx("p",{className:"text-[0.95rem] text-fg-dim leading-[1.8]",children:"They enabled an AI assistant with MCP access to their project management tool and email. Clients can now ask questions about their projects and get immediate, accurate answers with access to actual data. Complex questions still go to the manager. Routine ones get answered instantly by the AI."}),e.jsx("p",{className:"text-[0.95rem] text-fg-dim leading-[1.8]",children:"Result: The manager now spends 20 minutes weekly on client communication instead of 2.5 hours. But the clients are actually happier because they get instant responses to routine questions instead of waiting for replies."}),e.jsx("h2",{className:"font-serif font-normal text-[1.6rem] mb-4 mt-8",children:"How these add up"}),e.jsx("p",{className:"text-[0.95rem] text-fg-dim leading-[1.8]",children:"The interesting thing is that these aren't mutually exclusive. A single business might use AI to automate email handling, automate invoice processing, and handle customer follow-ups. The time savings compound."}),e.jsx("p",{className:"text-[0.95rem] text-fg-dim leading-[1.8]",children:"If you're a small business and you implement three of these automations, you're looking at 10-15 hours per week freed up. For a team of five people, that's roughly the equivalent of hiring one additional person, without the cost of hiring or the time to onboard."}),e.jsx("p",{className:"text-[0.95rem] text-fg-dim leading-[1.8]",children:"That time can go to business development. To client work. To actually growing. Or, if you prefer, to slightly less stressful weeks where your team goes home on time instead of catching up on repetitive work."}),e.jsxs("div",{className:"text-[0.7rem] tracking-[0.2em] uppercase text-fg-dim my-12 flex items-center gap-4",children:["Why it's happening now",e.jsx("span",{className:"flex-1 h-px bg-border"})]}),e.jsx("p",{className:"text-[0.95rem] text-fg-dim leading-[1.8]",children:"Five years ago, this would have been impossible without hiring a developer to build custom integrations for each system. Three years ago, it was possible but extremely expensive and required months of work."}),e.jsx("p",{className:"text-[0.95rem] text-fg-dim leading-[1.8]",children:"Now, with Model Context Protocol as a standard, you can connect your business tools to AI using a consistent pattern. No custom development. No months of setup. Four to six weeks from concept to production, typically."}),e.jsx("p",{className:"text-[0.95rem] text-fg-dim leading-[1.8]",children:"The MCP standard means that the tools you already use—Xero, HubSpot, Slack, Gmail, QuickBooks—can be connected to AI in a safe, auditable way. The AI can read your data. It can assist your team. It respects the permissions you've set. And it logs everything."}),e.jsxs("div",{className:"text-[0.7rem] tracking-[0.2em] uppercase text-fg-dim my-12 flex items-center gap-4",children:["Getting started for your business",e.jsx("span",{className:"flex-1 h-px bg-border"})]}),e.jsx("p",{className:"text-[0.95rem] text-fg-dim leading-[1.8]",children:"The first step is identifying where your time actually goes. Not in a theoretical way. But in the real way. What tasks does your team do repeatedly? What takes longer than it feels like it should? What do you hate doing but have to do?"}),e.jsx("p",{className:"text-[0.95rem] text-fg-dim leading-[1.8]",children:"Once you've identified one or two problem areas, you can assess whether connecting AI makes sense. Most small businesses find at least one workflow where the savings are obvious and achievable within weeks."}),e.jsxs("p",{className:"text-[0.95rem] text-fg-dim leading-[1.8]",children:[e.jsx(i,{to:"/ai-integration",className:"text-fg border-b border-border pb-px hover:border-accent transition-colors",children:"Talk to our team about where you could save time"})," ","with AI integration. We'll audit your workflows, identify your biggest opportunities, and show you exactly what's possible without building anything custom."]})]}),T=()=>e.jsxs("div",{className:"space-y-6",children:[e.jsx("p",{className:"text-[0.95rem] text-fg-dim leading-[1.8]",children:"Legal firms face a unique problem with AI. The technology is genuinely useful for document review, legal research, and contract analysis. But using it means handling sensitive client data. Confidential information. Privileged communications. And the rules around how that data is handled are non-negotiable."}),e.jsx("p",{className:"text-[0.95rem] text-fg-dim leading-[1.8]",children:"For years, this meant legal practices couldn't use AI for their core work. You couldn't send client documents to ChatGPT. You couldn't use cloud-based AI services without explicit client consent and complex data agreements. The compliance risk was too high."}),e.jsx("p",{className:"text-[0.95rem] text-fg-dim leading-[1.8]",children:"But that's changing. Model Context Protocol is making it possible for legal practices to use AI in ways that are actually compliant—where the data stays in your systems, where permissions are explicit and auditable, and where you maintain complete control over what information the AI sees."}),e.jsxs("div",{className:"text-[0.7rem] tracking-[0.2em] uppercase text-fg-dim my-12 flex items-center gap-4",children:["The compliance reality",e.jsx("span",{className:"flex-1 h-px bg-border"})]}),e.jsx("p",{className:"text-[0.95rem] text-fg-dim leading-[1.8]",children:"The Solicitors Regulation Authority and Bar Standards Board both have clear guidance on using third-party systems with client data. The bottom line: you need to understand what's happening with the data. You need written policies. You need to be able to demonstrate that confidentiality is maintained. And you need audit trails."}),e.jsx("p",{className:"text-[0.95rem] text-fg-dim leading-[1.8]",children:"Public cloud AI services create immediate problems. You send a document to ChatGPT, you've now sent it to a third party. Even if you have a data processing agreement in place, it's still outside your control. And in the UK legal context, that's a significant governance issue."}),e.jsx("p",{className:"text-[0.95rem] text-fg-dim leading-[1.8]",children:"Model Context Protocol solves this because the data never leaves your systems. The AI is connected via a secure protocol to your document management system, your case management software, your contracts database. The AI reads what you authorize it to read. Everything stays within your controlled environment. Every interaction is logged."}),e.jsx("blockquote",{className:"border-l-2 border-accent pl-6 my-8 text-fg italic font-serif text-[1.1rem]",children:"Compliance isn't a feature you add. It's how you build the system from the start. MCP is designed with that in mind."}),e.jsx("h2",{className:"font-serif font-normal text-[1.6rem] mb-4 mt-8",children:"What legal practices can actually do"}),e.jsx("p",{className:"text-[0.95rem] text-fg-dim leading-[1.8]",children:"Let's start with contract review. This is soul-crushing work. A junior lawyer receives a 40-page commercial agreement. They need to compare it to your standard template, identify deviations, flag unusual clauses, and summarize the key risks. This takes hours."}),e.jsx("p",{className:"text-[0.95rem] text-fg-dim leading-[1.8]",children:"With MCP connected to your document repository and your contract template database, an AI can handle the first pass. It reads the incoming contract. It compares it to your standard. It identifies deviations automatically. It flags clauses that differ from your norms in specific categories—liability caps, indemnity clauses, termination rights."}),e.jsx("p",{className:"text-[0.95rem] text-fg-dim leading-[1.8]",children:"A junior lawyer then reviews the AI's analysis and makes the final judgment calls. What previously took four hours now takes one hour. The lawyer is focused on the decisions that require legal judgment, not on the mechanical comparison work."}),e.jsx("p",{className:"text-[0.95rem] text-fg-dim leading-[1.8]",children:"The audit trail is perfect. You can show exactly what the AI reviewed, what it flagged, and when the human lawyer made the final assessment. That's SRA compliance. That's defensible."}),e.jsx("h2",{className:"font-serif font-normal text-[1.6rem] mb-4 mt-8",children:"Legal research with data access"}),e.jsx("p",{className:"text-[0.95rem] text-fg-dim leading-[1.8]",children:"Consider legal research. An associate needs to understand how UK courts have treated a specific indemnity clause in commercial agreements. Previously, they manually search case databases, read decisions, and synthesize findings."}),e.jsx("p",{className:"text-[0.95rem] text-fg-dim leading-[1.8]",children:"An AI connected to your firm's database of previous precedents, your case management system, and your legal research library can do something more efficient. It understands your specific practice area. It knows your past positions on similar clauses. It can synthesize your firm's precedent library along with broader legal research."}),e.jsx("p",{className:"text-[0.95rem] text-fg-dim leading-[1.8]",children:"The result is a comprehensive summary that includes both external legal authority and your firm's specific experience. And all of this happens entirely within your systems. The data never leaves your office."}),e.jsxs("div",{className:"text-[0.7rem] tracking-[0.2em] uppercase text-fg-dim my-12 flex items-center gap-4",children:["Due diligence automation",e.jsx("span",{className:"flex-1 h-px bg-border"})]}),e.jsx("p",{className:"text-[0.95rem] text-fg-dim leading-[1.8]",children:"For practices handling corporate transactions, due diligence is a massive undertaking. You're reviewing dozens of documents, identifying risks, compiling schedules. The work is necessary but it's not where you add legal value."}),e.jsx("p",{className:"text-[0.95rem] text-fg-dim leading-[1.8]",children:"An AI with MCP access to the target company's document room can read through everything automatically. It identifies financial commitments. It finds litigation references. It surfaces related-party transactions. It extracts key contract terms. It flags information gaps."}),e.jsx("p",{className:"text-[0.95rem] text-fg-dim leading-[1.8]",children:"Your team reviews the AI's findings, asks follow-up questions through the AI, and builds the actual findings memo. What might have taken two weeks of associate time now takes four days, with the associate focused entirely on analysis and judgment rather than document reading."}),e.jsx("h2",{className:"font-serif font-normal text-[1.6rem] mb-4 mt-8",children:"Client matter management"}),e.jsx("p",{className:"text-[0.95rem] text-fg-dim leading-[1.8]",children:"For practices with many active matters, the administrative overhead is significant. Tracking case deadlines. Monitoring document counts. Identifying when follow-up is needed. Managing file reviews."}),e.jsx("p",{className:"text-[0.95rem] text-fg-dim leading-[1.8]",children:"An AI connected to your case management system can manage much of this automatically. It alerts the responsible lawyer when key deadlines are approaching. It flags matters where documents haven't been updated in over 30 days. It creates summaries of case status for partners. It identifies matters that need client contact."}),e.jsx("p",{className:"text-[0.95rem] text-fg-dim leading-[1.8]",children:"This is operational efficiency that frees up time for actual legal work. And it doesn't require any new systems. It's just connecting your existing case management software to an AI assistant via MCP."}),e.jsxs("div",{className:"text-[0.7rem] tracking-[0.2em] uppercase text-fg-dim my-12 flex items-center gap-4",children:["The compliance and security framework",e.jsx("span",{className:"flex-1 h-px bg-border"})]}),e.jsx("p",{className:"text-[0.95rem] text-fg-dim leading-[1.8]",children:`Here's how this actually stays compliant. First, you define clear policies about what data the AI can access. Not "everything." But specific categories. For example: "The AI can read contracts and case documents, but not financial data or client personal information."`}),e.jsx("p",{className:"text-[0.95rem] text-fg-dim leading-[1.8]",children:"Second, the MCP server enforces those policies. The AI doesn't have a choice. It can only request the categories of data you've authorized. Anything else, it can't access. Period."}),e.jsx("p",{className:"text-[0.95rem] text-fg-dim leading-[1.8]",children:"Third, everything is logged. Every query the AI makes. Every document it reads. Every analysis it performs. For audit purposes, for compliance reviews, for showing SRA investigators if needed, you have the complete record."}),e.jsx("p",{className:"text-[0.95rem] text-fg-dim leading-[1.8]",children:"Fourth, the data stays within your environment. The AI isn't sending documents to an external server. It's not training on your data. It's just processing requests through a secure protocol that you control."}),e.jsx("p",{className:"text-[0.95rem] text-fg-dim leading-[1.8]",children:"From an SRA perspective, this is significantly stronger than many current manual processes. You have explicit policies. You have technical enforcement of those policies. You have audit trails. You have data residency within your systems. You maintain attorney-client privilege because the data never leaves your environment."}),e.jsxs("div",{className:"text-[0.7rem] tracking-[0.2em] uppercase text-fg-dim my-12 flex items-center gap-4",children:["Getting implementation right",e.jsx("span",{className:"flex-1 h-px bg-border"})]}),e.jsx("p",{className:"text-[0.95rem] text-fg-dim leading-[1.8]",children:"The implementation process is important. You don't just flip a switch. You start by identifying one specific workflow where AI would be genuinely useful and where compliance is straightforward."}),e.jsx("p",{className:"text-[0.95rem] text-fg-dim leading-[1.8]",children:"Maybe it's contract review. Maybe it's administrative matter management. Pick something bounded and well-understood. Build the MCP connection for that specific workflow. Test it thoroughly. Document your policies. Train your team. Then expand."}),e.jsx("p",{className:"text-[0.95rem] text-fg-dim leading-[1.8]",children:"The timeline is typically 4-8 weeks from planning to production for a single workflow. This assumes you have the technical capability internally or you're working with a specialist. Part of that time is designing the compliance framework, not just the technical setup."}),e.jsx("p",{className:"text-[0.95rem] text-fg-dim leading-[1.8]",children:"The outcome is a practice that's using AI in ways that are actually compliant, that improve efficiency significantly, and that maintain complete control over client data."}),e.jsx("h2",{className:"font-serif font-normal text-[1.6rem] mb-4 mt-8",children:"Why this matters for legal practices"}),e.jsx("p",{className:"text-[0.95rem] text-fg-dim leading-[1.8]",children:"Legal services are labor-intensive. The unit economics of a law firm depend on partner leverage—partners need associates doing work, associates need paralegals doing work. But the associate work that doesn't require legal judgment is being squeezed."}),e.jsx("p",{className:"text-[0.95rem] text-fg-dim leading-[1.8]",children:"AI doesn't change that dynamic if you're using cloud services for which you're concerned about data security. It only changes it if you can use AI safely within your systems. That's what MCP enables."}),e.jsx("p",{className:"text-[0.95rem] text-fg-dim leading-[1.8]",children:"A practice that implements AI via MCP can deliver work faster. Can charge clients more efficiently. Can free up junior lawyer time to develop judgment and client skills rather than document review. That's meaningful."}),e.jsxs("p",{className:"text-[0.95rem] text-fg-dim leading-[1.8]",children:[e.jsx(i,{to:"/ai-integration",className:"text-fg border-b border-border pb-px hover:border-accent transition-colors",children:"Discuss AI integration for your practice"})," ","with compliance considerations in mind. We'll help you identify the right workflows, design the governance framework, and implement the MCP connections safely and in ways that strengthen your compliance position."]})]}),C={"connect-ai-to-business-tools":e.jsx(N,{}),"ai-for-accounting-firms":e.jsx(k,{}),"why-ai-cant-see-your-crm":e.jsx(I,{}),"ai-saving-small-business-time":e.jsx(A,{}),"ai-for-legal-practices":e.jsx(T,{})},S=()=>{const{slug:a}=b();if(!a)return e.jsx(g,{to:"/blog",replace:!0});const t=v(a);if(!t)return e.jsx(g,{to:"/blog",replace:!0});const c=C[a];if(!c)return e.jsx(g,{to:"/blog",replace:!0});const d=t.dateISO||"2026-03-15";return e.jsx(j,{title:t.title,subtitle:t.subtitle,date:t.date,readTime:t.readTime,section:"blog",slug:a,tags:t.tags,dateISO:d,meta:{description:t.description,canonical:`/blog/${a}`,ogImage:"https://crox.io/og.png"},children:c})};export{S as default};
